   174	    private boolean isDuplicate(String topicArn, String deduplicationId) {
   175	        String cacheKey = topicArn + ":" + deduplicationId;
   176	        Instant now = Instant.now();
   177	        Instant existing = fifoDeduplicationCache.get(cacheKey);
   178	        if (existing != null && existing.plus(FIFO_DEDUP_WINDOW).isAfter(now)) {
   179	            return true;
   180	        }
   181	        fifoDeduplicationCache.put(cacheKey, now);
   182	        fifoDeduplicationCache.entrySet().removeIf(e -> e.getValue().plus(FIFO_DEDUP_WINDOW).isBefore(now));
   183	        return false;
   184	    }
