   186	    private List<Subscription> subscriptionsByTopic(String topicArn, String region) {
   187	        List<Subscription> result = new ArrayList<>();
   188	        String prefix = "sub::" + region + "::";
   189	        for (String k : subscriptionStore.keys()) {
   190	            if (k.startsWith(prefix)) {
   191	                subscriptionStore.get(k).ifPresent(sub -> {
   192	                    if (topicArn.equals(sub.getTopicArn())) result.add(sub);
   193	                });
   194	            }
   195	        }
   196	        return result;
   197	    }
