   199	    private void deliverMessage(Subscription sub, String message, String subject,
   200	                                Map<String, String> messageAttributes, String messageId,
   201	                                String topicArn, String messageGroupId) {
   202	        try {
   203	            switch (sub.getProtocol()) {
   204	                case "sqs" -> {
   205	                    String region = extractRegionFromArn(sub.getEndpoint());
   206	                    if (region == null) {
   207	                        region = extractRegionFromArn(topicArn);
   208	                    }
   209	                    String queueUrl = sqsArnToUrl(sub.getEndpoint());
   210	                    String envelope = buildSnsEnvelope(message, subject, messageAttributes, topicArn, messageId);
   211	                    sqsService.sendMessage(queueUrl, envelope, 0, messageGroupId, null, region);
   212	                    LOG.debugv("Delivered SNS message to SQS: {0} ({1}) in {2}",
   213	                            sub.getEndpoint(), queueUrl, region);
   214	                }
   215	                case "lambda" -> {
   216	                    String fnName = extractFunctionName(sub.getEndpoint());
   217	                    String region = extractRegionFromArn(sub.getEndpoint());
   218	                    String eventJson = buildSnsLambdaEvent(topicArn, messageId, message,
   219	                            subject, messageAttributes, sub.getSubscriptionArn());
   220	                    lambdaService.invoke(region, fnName, eventJson.getBytes(), InvocationType.Event);
   221	                    LOG.debugv("Delivered SNS message to Lambda: {0}", sub.getEndpoint());
   222	                }
   223	                case "email", "email-json" ->
   224	                    LOG.infov("SNS email delivery (stub): to={0}, subject={1}, message={2}",
   225	                            sub.getEndpoint(), subject, message);
   226	                case "sms" ->
   227	                    LOG.infov("SNS SMS delivery (stub): to={0}, message={1}", sub.getEndpoint(), message);
   228	                default -> LOG.debugv("Protocol {0} delivery not implemented, skipping: {1}",
   229	                        sub.getProtocol(), sub.getEndpoint());
   230	            }
   231	        } catch (Exception e) {
   232	            LOG.warnv("Failed to deliver SNS message to {0}: {1}", sub.getEndpoint(), e.getMessage());
   233	        }
   234	    }
