   236	    private String buildSnsLambdaEvent(String topicArn, String messageId, String message,
   237	                                       String subject, Map<String, String> messageAttributes,
   238	                                       String subscriptionArn) {
   239	        try {
   240	            String timestamp = DateTimeFormatter.ISO_INSTANT.format(Instant.now());
   241	            ObjectNode snsNode = objectMapper.createObjectNode();
   242	            snsNode.put("Type", "Notification");
   243	            snsNode.put("MessageId", messageId);
   244	            snsNode.put("TopicArn", topicArn);
   245	            if (subject != null) {
   246	                snsNode.put("Subject", subject);
   247	            } else {
   248	                snsNode.putNull("Subject");
   249	            }
   250	            snsNode.put("Message", message);
   251	            snsNode.put("Timestamp", timestamp);
   252	            snsNode.put("SignatureVersion", "1");
   253	            snsNode.put("Signature", "EXAMPLE");
   254	            snsNode.put("SigningCertUrl", "EXAMPLE");
   255	            snsNode.put("UnsubscribeUrl", "EXAMPLE");
   256	            ObjectNode attrs = snsNode.putObject("MessageAttributes");
   257	            if (messageAttributes != null) {
   258	                for (var entry : messageAttributes.entrySet()) {
   259	                    ObjectNode attr = attrs.putObject(entry.getKey());
   260	                    attr.put("Type", "String");
   261	                    attr.put("Value", entry.getValue());
   262	                }
   263	            }
   264	            ObjectNode record = objectMapper.createObjectNode();
   265	            record.put("EventVersion", "1.0");
   266	            record.put("EventSubscriptionArn", subscriptionArn);
   267	            record.put("EventSource", "aws:sns");
   268	            record.set("Sns", snsNode);
   269	            ObjectNode root = objectMapper.createObjectNode();
   270	            root.putArray("Records").add(record);
   271	            return objectMapper.writeValueAsString(root);
   272	        } catch (Exception e) {
   273	            return "{\"Records\":[]}";
   274	        }
   275	    }
