   282	    private static String extractRegionFromArn(String arn) {
   283	        if (arn == null || !arn.startsWith("arn:aws:")) return null;
   284	        String[] parts = arn.split(":");
   285	        return parts.length >= 4 ? parts[3] : null;
   286	    }
