   288	    private String buildSnsEnvelope(String message, String subject,
   289	                                    Map<String, String> messageAttributes,
   290	                                    String topicArn, String messageId) {
   291	        try {
   292	            ObjectNode node = objectMapper.createObjectNode();
   293	            node.put("Type", "Notification");
   294	            node.put("MessageId", messageId);
   295	            node.put("TopicArn", topicArn);
   296	            if (subject != null) {
   297	                node.put("Subject", subject);
   298	            }
   299	            node.put("Message", message);
   300	            ObjectNode attrs = node.putObject("MessageAttributes");
   301	            if (messageAttributes != null) {
   302	                for (var entry : messageAttributes.entrySet()) {
   303	                    ObjectNode attr = attrs.putObject(entry.getKey());
   304	                    attr.put("Type", "String");
   305	                    attr.put("Value", entry.getValue());
   306	                }
   307	            }
   308	            return objectMapper.writeValueAsString(node);
   309	        } catch (Exception e) {
   310	            return "{}";
   311	        }
   312	    }
   313	
   314	    private String sqsArnToUrl(String arn) {
   315	        if (arn == null) return null;
   316	        if (arn.startsWith("http")) return arn;
   317	        if (arn.split(":").length < 6) return arn;
   318	        return AwsArnUtils.arnToQueueUrl(arn, baseUrl);
   319	    }
