   321	    private static String sha256(String message) {
   322	        try {
   323	            MessageDigest md = MessageDigest.getInstance("SHA-256");
   324	            byte[] hash = md.digest(message.getBytes(StandardCharsets.UTF_8));
   325	            var sb = new StringBuilder();
   326	            for (byte b : hash) {
   327	                sb.append(String.format("%02x", b));
   328	            }
   329	            return sb.toString();
   330	        } catch (NoSuchAlgorithmException e) {
   331	            return UUID.randomUUID().toString();
   332	        }
   333	    }
   334	
   335	    private static String topicKey(String region, String arn) {
   336	        return "topic::" + region + "::" + arn;
   337	    }
   338	
   339	    private static String subKey(String region, String subscriptionArn) {
   340	        return "sub::" + region + "::" + subscriptionArn;
   341	    }
